import { Outlet } from "react-router-dom";
import Sidebar from "./Sidebar";
import { useAuth } from "../AuthContext";

export default function Layout() {
    const { user, logout } = useAuth();

    return (
        <div className="flex h-screen bg-slate-50">
            <Sidebar />
            <div className="flex-1 flex flex-col">
                {/* Header */}
                <header className="h-14 bg-white border-b border-slate-200 px-4 flex items-center justify-between">
                    <div className="font-semibold">Hệ thống quản lý KH & Hợp đồng</div>
                    <div className="flex items-center gap-3">
                        <div className="text-sm">
                            <div className="font-medium">{user?.username}</div>
                            <div className="text-slate-500 text-xs">
                                {user?.roles?.join(", ")}
                            </div>
                        </div>
                        <button
                            onClick={logout}
                            className="px-3 py-1.5 rounded-lg bg-slate-100 hover:bg-slate-200 text-sm"
                        >
                            Đăng xuất
                        </button>
                    </div>
                </header>

                {/* Nội dung trang */}
                <main className="flex-1 overflow-auto">
                    <Outlet />
                </main>
            </div>
        </div>
    );
}
